// DEMO: Rule-based triage (production: replace with Claude via HTTP Request node)
const item = $input.item.json;
const desc = (item.issue_description || '').toLowerCase();
const stated = (item.stated_urgency || '').toLowerCase();

let urgency = 'routine';
let category = 'other';
let vendor_category = 'general';
let reasoning = '';

// Emergency keywords
if (desc.match(/flood|flooding|burst|sewage|gas leak|fire|no heat.*cold|freezing/)) {
  urgency = 'emergency';
  reasoning = 'Flooding, burst pipe, or life-safety issue detected.';
} else if (stated === 'emergency') {
  urgency = 'emergency';
  reasoning = 'Tenant reported as emergency.';
// Urgent keywords
} else if (desc.match(/no heat|no hot water|heater.*stop|hvac.*fail|not working|no power|electrical.*out/) || stated === 'high') {
  urgency = 'urgent';
  reasoning = 'Critical system failure affecting habitability.';
} else {
  urgency = 'routine';
  reasoning = 'Non-critical maintenance request.';
}

// Category
if (desc.match(/faucet|pipe|toilet|drain|water|plumb|leak/)) {
  category = 'plumbing'; vendor_category = urgency === 'emergency' ? 'emergency' : 'plumbing';
} else if (desc.match(/heat|hvac|ac|air|cool|furnace|boiler/)) {
  category = 'hvac'; vendor_category = urgency === 'emergency' ? 'emergency' : 'hvac';
} else if (desc.match(/electric|power|outlet|light|switch|breaker/)) {
  category = 'electrical'; vendor_category = urgency === 'emergency' ? 'emergency' : 'electrical';
} else if (desc.match(/door|window|lock|wall|roof|ceiling|floor|struc/)) {
  category = 'structural'; vendor_category = urgency === 'emergency' ? 'emergency' : 'general';
} else if (desc.match(/paint|scratch|scuff|cosmetic|dent|minor/)) {
  category = 'cosmetic'; vendor_category = 'general';
} else if (desc.match(/refrigerator|fridge|stove|oven|dishwasher|washer|dryer|microwave/)) {
  category = 'appliance'; vendor_category = 'general';
} else if (desc.match(/bug|insect|pest|rodent|mice|mouse|rat|roach|bedbug/)) {
  category = 'pest'; vendor_category = 'general';
}

return { ...item, urgency, category, vendor_category, reasoning };

